        count = {}
        for num in nums:
            if num in count:
                count[num] += 1
            else:
                count[num] = 1
        for num in nums:
            if count[num] > 0:
                seq = num
                count[num] -= 1
                while count.get(seq + 1, 0) > 0:
                    seq += 1
                    count[seq] -= 1
                if count.get(seq + 1, 0) > 0 and count.get(seq + 2, 0) > 0:
                    count[seq + 1] -= 1
                    count[seq + 2] -= 1
                else:
                    return False
        return True
